char const * dx9_post_vertex =
	"// Copyright (c) 2007 by Tech Soft 3D, LLC.\n"
	"// all rights reserved\n"
	"// $Id: h3d_hlsl.h,v 1.1820.2.103 2011-01-28 04:37:39 stage Exp $\n"
	" \n"
	"/* IO Types ******************************************************************/\n"
	"\n"
	"/* \n"
	" * VERTEX\n"
	" * Input from vertex buffer \n"
	" */\n"
	"struct Vertex\n"
	"{\n"
	"	/* Vertex position */\n"
	"	float3 position : POSITION;\n"
	"};\n"
	"\n"
	"\n"
	"/* \n"
	" * ITERATOR\n"
	" * Output to triangle setup \n"
	" */\n"
	"struct Iterator\n"
	"{\n"
	"	/* Transformed vertex position */\n"
	"	float4 position : POSITION;\n"
	"	\n"
	"	/* Texture coordinate */\n"
	"	float4 screen_uv : TEXCOORD0;\n"
	"};\n"
	"\n"
	"/* Uniforms ******************************************************************/\n"
	"\n"
	"/* Depth value */\n"
	"float ConstantDepth;\n"
	"\n"
	"/* 2D offset to centre pixels on texels correctly */\n"
	"float2 TexelOffset;\n"
	"\n"
	"/* Code **********************************************************************/\n"
	"\n"
	"Iterator main( const Vertex vertex )\n"
	"{\n"
	"	Iterator result;\n"
	"\n"
	"	// Assemble position with fixed depth and no perspective divide.\n"
	"	float4 position = float4(vertex.position.xy,ConstantDepth,1);\n"
	"	result.position = position;\n"
	"	\n"
	"    // Map NDC space into unit square UV space\n"
	"	result.screen_uv = position * 0.5f + 0.5f;\n"
	"	result.screen_uv.xy += TexelOffset;\n"
	"	result.screen_uv.y = 1 - result.screen_uv.y;\n"
	"    \n"
	"	// Done\n"
	"	return result;\n"
	"} \n"
	"\n"
; 


char const * dx9_post_vertex_3d =
	"// Copyright (c) 2007 by Tech Soft 3D, LLC.\n"
	"// all rights reserved\n"
	"// $Id: h3d_hlsl.h,v 1.1820.2.103 2011-01-28 04:37:39 stage Exp $\n"
	" \n"
	"/* IO Types ******************************************************************/\n"
	"\n"
	"/* \n"
	" * VERTEX\n"
	" * Input from vertex buffer \n"
	" */\n"
	"struct Vertex\n"
	"{\n"
	"	/* Vertex position */\n"
	"	float3 position : POSITION;\n"
	"};\n"
	"\n"
	"\n"
	"/* \n"
	" * ITERATOR\n"
	" * Output to triangle setup \n"
	" */\n"
	"struct Iterator\n"
	"{\n"
	"	/* Transformed vertex position */\n"
	"	float4 position : POSITION;\n"
	"	\n"
	"	/* Texture coordinate */\n"
	"	float2 uv : TEXCOORD0;\n"
	"	\n"
	"	/* Texture coordinate */\n"
	"	float4 vpos : TEXCOORD1;\n"
	"};\n"
	"\n"
	"/* Uniforms ******************************************************************/\n"
	"\n"
	"/* Depth value */\n"
	"float ConstantDepth;\n"
	"float4x4 ModelToProjection;\n"
	"\n"
	"/* Code **********************************************************************/\n"
	"\n"
	"Iterator main( const Vertex vertex )\n"
	"{\n"
	"	Iterator result;\n"
	"\n"
	"	// Assemble and transform position\n"
	"	float4 position = mul(float4(vertex.position.xy,0,1), ModelToProjection);\n"
	"	\n"
	"	// Output a position at a fixed depth, working around perspective divide\n"
	"	result.position = float4(position.xy, ConstantDepth * position.w, position.w);\n"
	"	    \n"
	"    // Map NDC space into unit square UV space\n"
	"	result.uv = vertex.position.xy * 0.5 + 0.5;\n"
	"	result.uv.y = 1 - result.uv.y;\n"
	"	result.vpos = position;\n"
	"	\n"
	"	// Done\n"
	"	return result;\n"
	"} \n"
	"\n"
; 


