char const * _hoops_CRIAH =
	"// Copyright (c) 2007 by Tech Soft 3D, LLC.\n"
	"// all rights reserved\n"
	"// $Id: h3d_hlsl.h,v 1.1820.2.103 2011-01-28 04:37:39 stage Exp $\n"
	" \n"
	"// Copyright (c) 2007 by Tech Soft 3D, LLC.\n"
	"// all rights reserved\n"
	"// $Id: h3d_hlsl.h,v 1.1820.2.103 2011-01-28 04:37:39 stage Exp $\n"
	" \n"
	"#ifndef NUM_TAPS\n"
	"#error NUM_TAPS must be defined to use this shader!\n"
	"#endif // NUM_TAPS\n"
	" \n"
	"/* Uniforms ******************************************************************/\n"
	"\n"
	"uniform sampler2D Sampler reg(s0);\n"
	"uniform const float4 Kernel[NUM_TAPS];\n"
	"\n"
	"#define CENTRE_WEIGHT (1.414*112.0/256.0)\n"
	"\n"
	"/* Code **********************************************************************/\n"
	"\n"
	"void post_pixel(\n"
	"	float2 in_uv,\n"
	"	out float4 result)\n"
	"{\n"
	"	float4 centre = tex2D(Sampler, in_uv);\n"
	"	\n"
	"	// Initialise accumulator\n"
	"	float total_weight = CENTRE_WEIGHT;\n"
	"	result = centre * CENTRE_WEIGHT;\n"
	"\n"
	"	for ( int i = 0; i < NUM_TAPS; ++i )\n"
	"	{\n"
	"		float2 uv = in_uv + Kernel[i].xy;\n"
	"		float4 sample = tex2D(Sampler, uv);\n"
	"		\n"
	"		// Accumulate weighted by centre's blue channel. \n"
	"		result += Kernel[i].w * sample * centre.b;\n"
	"		total_weight += Kernel[i].w;\n"
	"	}\n"
	"	\n"
	"	// Normalise\n"
	"	result /= total_weight;\n"
	"\n"
	"	// Don't filter the output blue channel\n"
	"	result.b = centre.b;\n"
	"} \n"
	"\n"
; 


char const * _hoops_SRIAH =
	"// Copyright (c) 2007 by Tech Soft 3D, LLC.\n"
	"// all rights reserved\n"
	"// $Id: h3d_hlsl.h,v 1.1820.2.103 2011-01-28 04:37:39 stage Exp $\n"
	" \n"
	"/* IO Types ******************************************************************/\n"
	"\n"
	"\n"
	"/* Uniforms ******************************************************************/\n"
	"\n"
	"uniform sampler2D Scene reg(s0);\n"
	"\n"
	"/* Code **********************************************************************/\n"
	"\n"
	"void post_pixel(\n"
	"	float2 in_uv,\n"
	"	out float4 result)\n"
	"{\n"
	"	float4 pixel = tex2D( Scene, in_uv );\n"
	"	\n"
	"	// Convert nonzero luminance into 1.0 alpha\n"
	"	float mask = float(pixel.a != 0.0);\n"
	"	result = float4(mask, mask, mask, mask);\n"
	"} \n"
	"\n"
; 


char const * _hoops_PRIAH =
	"// Copyright (c) 2007 by Tech Soft 3D, LLC.\n"
	"// all rights reserved\n"
	"// $Id: h3d_hlsl.h,v 1.1820.2.103 2011-01-28 04:37:39 stage Exp $\n"
	" \n"
	"/* Uniforms ******************************************************************/\n"
	"\n"
	"uniform sampler2D Depth reg(s0);\n"
	"uniform sampler2D Scene reg(s1);\n"
	"\n"
	"uniform float3 EyeDir;\n"
	"\n"
	"#define ReliefMapDepth 1.0\n"
	"\n"
	"/* Code **********************************************************************/\n"
	"\n"
	"// Ray marching code from Fabio Policarpo's original relief mapping paper.\n"
	"\n"
	"// setup ray pos and dir based on view vector\n"
	"// and apply depth bias and depth factor\n"
	"void setup_ray(in float2 uv,out float3 p,out float3 v)\n"
	"{\n"
	"	p = float3(uv,0.0);\n"
	"	v = normalize(EyeDir);\n"
	"	\n"
	"	v.z = abs(v.z);\n"
	"\n"
	"	v.xy *= ReliefMapDepth;\n"
	"}\n"
	"\n"
	"// ray intersect depth map using linear and binary searches\n"
	"// depth value stored in alpha channel (black at is object surface)\n"
	"void ray_intersect_relief(\n"
	"	sampler2D relief_map,\n"
	"	inout float3 p,\n"
	"	inout float3 v)\n"
	"{\n"
	"// SM3\n"
	"	// const int num_steps_lin=12;\n"
	"	// const int num_steps_bin=6;\n"
	"\n"
	"// SM2\n"
	"	const int num_steps_lin=2;\n"
	"	const int num_steps_bin=1;\n"
	"	\n"
	"	v /= v.z*num_steps_lin;\n"
	"	\n"
	"	int i;\n"
	"	for( i=0;i<num_steps_lin;i++ )\n"
	"	{\n"
	"		float4 tex = tex2D(relief_map, p.xy);\n"
	"		if (p.z<tex.x)\n"
	"			p+=v;\n"
	"	}\n"
	"	\n"
	"	for( i=0;i<num_steps_bin;i++ )\n"
	"	{\n"
	"		v *= 0.5;\n"
	"		float4 tex = tex2D(relief_map, p.xy);\n"
	"		if (p.z<tex.x)\n"
	"			p+=v;\n"
	"		else\n"
	"			p-=v;\n"
	"	}\n"
	"}\n"
	"\n"
	"void post_pixel( \n"
	"	float2 in_uv,\n"
	"	out float4 color,\n"
	"	out float depth)\n"
	"{\n"
	"	float3 p,v;\n"
	"	\n"
	"	setup_ray(in_uv,p,v);\n"
	"\n"
	"	ray_intersect_relief(Depth,p.xyz,v);\n"
	"\n"
	"	color = tex2D(Scene, p.xy);\n"
	"	depth = tex2D(Depth, p.xy).r;\n"
	"	\n"
	"// For verification\n"
	"//	color = float4(uv, 0, 0);\n"
	"//	color = float4(iterator.normal,1);\n"
	"//	color = float4(EyeDir,1);\n"
	"} \n"
	"\n"
; 


char const * _hoops_SGIAH =
	"// Copyright (c) 2007 by Tech Soft 3D, LLC.\n"
	"// all rights reserved\n"
	"// $Id: h3d_hlsl.h,v 1.1820.2.103 2011-01-28 04:37:39 stage Exp $\n"
	" \n"
	"/* Uniforms ******************************************************************/\n"
	"\n"
	"uniform sampler2D Depth reg(s0);\n"
	"\n"
	"uniform float2 OneOverTexelSize;\n"
	"uniform float2 ToleranceScaleAndBias;\n"
	"uniform float2 Taps[4];\n"
	"uniform float DepthScale;\n"
	"uniform float3 EdgeColor;\n"
	"\n"
	"#define ONE float4(1.0, 1.0, 1.0, 1.0)\n"
	"\n"
	"/* Code **********************************************************************/\n"
	"\n"
	"void post_pixel(\n"
	"	float2 uv,\n"
	"	out float4 result)\n"
	"{\n"
	"	const float sharp = unpack_rgba(tex2D(Depth, uv));\n"
	"	\n"
	"	float silhouette = 0.0;\n"
	"	\n"
	"	if (sharp != 1.0)\n"
	"	{\n"
	"		float4 samples;\n"
	"		samples.x = unpack_rgba(tex2D( Depth, uv + Taps[0] * OneOverTexelSize ));\n"
	"		samples.y = unpack_rgba(tex2D( Depth, uv + Taps[1] * OneOverTexelSize ));\n"
	"		samples.z = unpack_rgba(tex2D( Depth, uv + Taps[2] * OneOverTexelSize ));\n"
	"		samples.w = unpack_rgba(tex2D( Depth, uv + Taps[3] * OneOverTexelSize ));\n"
	"	\n"
	"		// Compute deltas\n"
	"		float4 deltas = abs(samples - float4(sharp, sharp, sharp, sharp)) * DepthScale;\n"
	"	\n"
	"		// Invalidate any excluded samples\n"
	"#ifdef DX9\n"
	"		deltas *= float4(notEqual(samples, ONE));\n"
	"#else\n"
	"		if (samples.x == 1.0)\n"
	"			deltas.x = 0.0;\n"
	"		if (samples.y == 1.0)\n"
	"			deltas.y = 0.0;\n"
	"		if (samples.z == 1.0)\n"
	"			deltas.z = 0.0;\n"
	"		if (samples.w == 1.0)\n"
	"			deltas.w = 0.0;\n"
	"#endif\n"
	"	\n"
	"		// Take maximum\n"
	"		float max_delta = max(max(deltas.x, deltas.y), max(deltas.z, deltas.w));\n"
	"\n"
	"		// Generate smooth silhouette value from active range.\n"
	"		silhouette = saturate(max_delta * ToleranceScaleAndBias.x + ToleranceScaleAndBias.y);\n"
	"	}\n"
	"	\n"
	"	// Darken via blend.\n"
	"	result = float4(EdgeColor.r, EdgeColor.g, EdgeColor.b, silhouette);\n"
	"} \n"
; 


